window.CARDS=[{"id": "Abbe's Diffraction Limit", "name": "Abbe's Diffraction Limit", "kind": "Model", "year": 1873, "place": "Jena, Germany", "person": "Ernst Abbe", "sig": "Abbe's formula turned lens design from guesswork into calculation, making Jena the center of world optics for generations and drawing the exact wall that forced the jump to electron microscopes.", "goal": "1", "mech": "Convergence", "threads": ["Precision Optics", "Microscopy"], "primary": "Precision Optics", "lat": 50.93, "lon": 11.59, "bo": ["Leeuwenhoek's Microscope", "Fraunhofer's Spectral-Line Glass"], "en": ["The Matter Wave", "Photolithography", "The Foldscope"], "country": ""}, {"id": "AlexNet", "name": "AlexNet", "kind": "Make", "year": 2012, "place": "Toronto, Canada", "person": "Krizhevsky, Sutskever, and Hinton", "sig": "AlexNet cut image-recognition error by 10 points over the field in 2012, proving that deep networks on consumer GPUs worked at scale and triggering nearly every serious lab to switch methods within a year.", "goal": "Both", "mech": "Convergence", "threads": ["Machine Learning"], "primary": "Machine Learning", "lat": 43.65, "lon": -79.38, "bo": ["The GPU", "Backpropagation", "ImageNet"], "en": ["The Transformer"], "country": ""}, {"id": "AlphaFold", "name": "AlphaFold", "kind": "Model", "year": 2020, "place": "London, England", "person": "Demis Hassabis and John Jumper", "sig": "AlphaFold replaced months of X-ray crystallography with hours of computation, putting the shapes of 200 million proteins online for free and moving the lead in structural biology to whoever can train the model.", "goal": "Both", "mech": "Convergence", "threads": ["Reading & Writing DNA", "Predict Before Building"], "primary": "Reading & Writing DNA", "lat": 51.51, "lon": -0.13, "bo": ["X-ray Crystallography", "Cryo-EM", "The Deep-Learning Framework", "The Transformer"], "en": [], "country": ""}, {"id": "Antibiotic Fermentation", "name": "Antibiotic Fermentation", "kind": "Manufacture", "year": 2004, "place": "Shijiazhuang, China", "person": "North China Pharmaceutical and the Chinese fermentation plants", "sig": "Industrial antibiotic fermentation grows the 6-APA and 7-ACA core that nearly all penicillins and cephalosporins are built from, and the West let the tool migrate to China so completely that the last US penicillin plant closed in 2004.", "goal": "Both", "mech": "Pace-layers", "threads": ["Therapeutics"], "primary": "Therapeutics", "lat": 38.04, "lon": 114.51, "bo": ["Deep-Tank Fermentation"], "en": [], "country": ""}, {"id": "Atomic Layer Deposition", "name": "Atomic Layer Deposition", "kind": "Manufacture", "year": 1974, "place": "Helsinki, Finland", "person": "Tuomo Suntola", "sig": "Atomic layer deposition grows a film one atomic layer at a time using gas reactions that stop themselves once a single layer is laid, the only way to coat the most advanced chips with the exact thinness they need.", "goal": "Both", "mech": "Convergence", "threads": ["Chip Lithography"], "primary": "Chip Lithography", "lat": 60.17, "lon": 24.94, "bo": ["The Integrated Circuit"], "en": [], "country": ""}, {"id": "Backpropagation", "name": "Backpropagation", "kind": "Model", "year": 1986, "place": "San Diego, California, USA", "person": "Rumelhart, Hinton, and Williams", "sig": "Backpropagation gave neural networks a way to learn their own features from examples rather than hand-coded rules, but the method sat idle for 25 years until cheap GPUs made it practical, so the lead pooled in compute, not the equation.", "goal": "Both", "mech": "Fragility", "threads": ["Machine Learning"], "primary": "Machine Learning", "lat": 32.72, "lon": -117.16, "bo": [], "en": ["The Deep-Learning Framework", "AlexNet"], "country": ""}, {"id": "Battery-Line Equipment", "name": "Battery-Line Equipment", "kind": "Manufacture", "year": 2024, "place": "Wuxi, China", "person": "Wuxi Lead Intelligent Equipment", "sig": "The machine that turns electrode paste into a finished cell ships from Wuxi to Tesla and Arizona alike, so the lead does not live in the line but in the seconded cadre who can ramp it to yield.", "goal": "Both", "mech": "Pace-layers", "threads": ["Electricity & Batteries"], "primary": "Electricity & Batteries", "lat": 31.49, "lon": 120.31, "bo": ["The Graphite Anode"], "en": [], "country": ""}, {"id": "CATIA", "name": "CATIA", "kind": "Model", "year": 1977, "place": "Paris, France", "person": "Dassault engineers", "sig": "CATIA turned Sutherland's American design idea into the standard tool of world aerospace, a lead that crossed the Atlantic and stayed in French hands.", "goal": "Both", "mech": "Pace-layers", "threads": ["Prototyping & CAD"], "primary": "Prototyping & CAD", "lat": 48.86, "lon": 2.35, "bo": ["Sketchpad"], "en": ["The Falcon 9"], "country": ""}, {"id": "CRISPR-Cas9", "name": "CRISPR-Cas9", "kind": "Make", "year": 2012, "place": "Berkeley, California, USA", "person": "Jennifer Doudna and Emmanuelle Charpentier", "sig": "CRISPR replaced expensive custom-protein tools with a short typed tag, cutting the cost of a targeted DNA edit by roughly 150 times and concentrating the editing lead in the Bay Area and Boston biotech clusters where the tool was commercialized.", "goal": "Both", "mech": "Convergence", "threads": ["Reading & Writing DNA", "Engineering Biology"], "primary": "Reading & Writing DNA", "lat": 37.87, "lon": -122.27, "bo": ["DNA Sequencing", "DNA Synthesis", "PCR"], "en": [], "country": ""}, {"id": "Computational Fluid Dynamics", "name": "Computational Fluid Dynamics", "kind": "Model", "year": 1979, "place": "Mountain View, California, USA", "person": "Dean Chapman", "sig": "CFD let Boeing cut wind-tunnel test rounds from 77 to 10 on the 777, showing that cheap compute could replace much of physical testing and keeping the aircraft design lead where the supercomputers were.", "goal": "Both", "mech": "Convergence", "threads": ["Predict Before Building", "Flight"], "primary": "Predict Before Building", "lat": 37.41, "lon": -122.06, "bo": ["The Variable-Density Tunnel"], "en": [], "country": ""}, {"id": "Cryo-EM", "name": "Cryo-EM", "kind": "Measure", "year": 1984, "place": "Heidelberg, Germany", "person": "Jacques Dubochet, Joachim Frank, Richard Henderson", "sig": "Cryo-EM flash-freezes a molecule in glassy ice and rebuilds its shape from thousands of electron-microscope images, solving structures too big or too floppy to crystallize, the modern rival to X-ray crystallography.", "goal": "Both", "mech": "Convergence", "threads": ["Materials Characterization", "Electron Microscopy"], "primary": "Materials Characterization", "lat": 49.4, "lon": 8.67, "bo": ["The Electron Microscope", "The Scanning Tunneling Microscope"], "en": ["AlphaFold"], "country": ""}, {"id": "DNA Sequencing", "name": "DNA Sequencing", "kind": "Measure", "year": 1977, "place": "Cambridge, England", "person": "Frederick Sanger", "sig": "Sanger's 1977 method made it possible to read the order of DNA letters for the first time, opening a four-decade cost collapse that moved the sequencing lead from Cambridge to San Diego's Illumina and now into contest with China's BGI.", "goal": "Both", "mech": "Convergence", "threads": ["Reading & Writing DNA"], "primary": "Reading & Writing DNA", "lat": 52.2, "lon": 0.12, "bo": ["The Laser", "Gel Electrophoresis", "Recombinant DNA"], "en": ["CRISPR-Cas9", "Next-Generation Sequencing"], "country": ""}, {"id": "DNA Synthesis", "name": "DNA Synthesis", "kind": "Make", "year": 1981, "place": "Boulder, Colorado, USA", "person": "Marvin Caruthers", "sig": "Caruthers' phosphoramidite chemistry let a machine write a chosen DNA sequence one base at a time in hours, the write half of biology that pairs with reading it.", "goal": "Both", "mech": "Convergence", "threads": ["Reading & Writing DNA", "Engineering Biology"], "primary": "Reading & Writing DNA", "lat": 40.01, "lon": -105.27, "bo": [], "en": ["DNA-Encoded Libraries", "PCR", "CRISPR-Cas9"], "country": ""}, {"id": "DNA-Encoded Libraries", "name": "DNA-Encoded Libraries", "kind": "Make", "year": 1992, "place": "La Jolla, USA", "person": "Sydney Brenner and Richard Lerner", "sig": "It turns drug screening from a one-at-a-time grind into a single pooled experiment read out by sequencing.", "goal": "Both", "mech": "Convergence", "threads": ["Therapeutics"], "primary": "Therapeutics", "lat": 32.8328, "lon": -117.2713, "bo": ["DNA Synthesis", "Next-Generation Sequencing"], "en": [], "country": ""}, {"id": "DRAM", "name": "DRAM", "kind": "Make", "year": 1966, "place": "Yorktown Heights, New York, USA", "person": "Robert Dennard", "sig": "DRAM stores each bit as a speck of charge held by one tiny transistor, the cheap memory in every computer, and the commodity whose manufacturing lead slid from America to Japan to Korea.", "goal": "Both", "mech": "Pace-layers", "threads": ["Electronic Switching"], "primary": "Electronic Switching", "lat": 41.27, "lon": -73.77, "bo": ["The MOSFET"], "en": [], "country": ""}, {"id": "Deep-Tank Fermentation", "name": "Deep-Tank Fermentation", "kind": "Manufacture", "year": 1944, "place": "Peoria, Illinois, USA", "person": "Andrew Moyer and the Peoria lab", "sig": "Submerged deep-tank fermentation is the tool that turned penicillin from a milligram-a-week lab curiosity into the first mass-produced antibiotic, and it moved drug-making leadership from Britain to America.", "goal": "Both", "mech": "Convergence", "threads": ["Therapeutics", "Forced by War"], "primary": "Therapeutics", "lat": 40.69, "lon": -89.59, "bo": [], "en": ["Antibiotic Fermentation", "The Single-Use Bioreactor"], "country": ""}, {"id": "Density Functional Theory", "name": "Density Functional Theory", "kind": "Model", "year": 1965, "place": "San Diego, California, USA", "person": "Walter Kohn", "sig": "Density functional theory made it possible to calculate a material's properties from the quantum behavior of its electrons, turning materials science from wet-lab trial and error into something you can compute.", "goal": "Both", "mech": "Convergence", "threads": ["Predict Before Building"], "primary": "Predict Before Building", "lat": 32.72, "lon": -117.16, "bo": [], "en": ["GNoME"], "country": ""}, {"id": "Einstein's Displacement Equation", "name": "Einstein's Displacement Equation", "kind": "Model", "year": 1905, "place": "Bern, Switzerland", "person": "Albert Einstein", "sig": "Einstein's 1905 equation tied the distance a suspended speck wanders to the number of atoms in matter, turning a microscope and a stopwatch into an atom-counting instrument, though the formula was free and gave no one a lasting lead.", "goal": "1", "mech": "Convergence", "threads": ["Atomic Theory"], "primary": "Atomic Theory", "lat": 46.95, "lon": 7.45, "bo": ["Leeuwenhoek's Microscope", "The Spectroscope"], "en": ["The Mass Spectrograph"], "country": ""}, {"id": "Electronic Design Automation", "name": "Electronic Design Automation", "kind": "Model", "year": 1980, "place": "Pasadena, California, USA", "person": "Carver Mead and Lynn Conway", "sig": "Turning chip design into software split designing a chip from making it, creating the fabless-and-foundry model, and the design tools settled into three American firms that still hold most of the market.", "goal": "Both", "mech": "Convergence", "threads": ["Prototyping & CAD", "Chip Lithography"], "primary": "Prototyping & CAD", "lat": 34.15, "lon": -118.14, "bo": ["The Integrated Circuit", "Sketchpad"], "en": ["The High-Yield Process Recipe"], "country": ""}, {"id": "Ethernet", "name": "Ethernet", "kind": "Make", "year": 1973, "place": "Palo Alto, USA", "person": "Robert Metcalfe and David Boggs", "sig": "It let a room full of computers share one cable by taking turns, and became the way local networks were wired.", "goal": "Both", "mech": "Convergence", "threads": ["The Network"], "primary": "The Network", "lat": 37.4, "lon": -122.15, "bo": ["The Router"], "en": ["TCP-IP"], "country": ""}, {"id": "FORTRAN", "name": "FORTRAN", "kind": "Model", "year": 1957, "place": "New York, New York, USA", "person": "John Backus", "sig": "FORTRAN's optimizing compiler proved a program written in plain math could run nearly as fast as hand-tuned machine code, so software finally split from the one machine it was written for.", "goal": "Both", "mech": "Convergence", "threads": ["Software Abstraction"], "primary": "Software Abstraction", "lat": 40.71, "lon": -74.01, "bo": ["The Punch Card"], "en": ["Unix and C", "Smalltalk"], "country": ""}, {"id": "Faraday's Induction Ring", "name": "Faraday's Induction Ring", "kind": "Make", "year": 1831, "place": "London, England", "person": "Michael Faraday", "sig": "Faraday's iron ring showed that a changing magnetic field makes a current, the principle every generator, motor, and transformer on Earth is built from.", "goal": "Both", "mech": "Convergence", "threads": ["Electricity & Batteries"], "primary": "Electricity & Batteries", "lat": 51.51, "lon": -0.13, "bo": ["Volta's Pile"], "en": [], "country": ""}, {"id": "Flow Chemistry", "name": "Flow Chemistry", "kind": "Manufacture", "year": 2016, "place": "Cambridge, USA", "person": "Klavs Jensen, Timothy Jamison, Allan Myerson (MIT)", "sig": "It is the modern way to build drug molecules at scale, and it shows how far the West has let the actual making of medicine drift away.", "goal": "Both", "mech": "Fragility", "threads": ["Therapeutics"], "primary": "Therapeutics", "lat": 42.3601, "lon": -71.0942, "bo": ["The Single-Use Bioreactor"], "en": ["Lipid Nanoparticles"], "country": ""}, {"id": "Fraunhofer's Spectral-Line Glass", "name": "Fraunhofer's Spectral-Line Glass", "kind": "Measure", "year": 1814, "place": "Benediktbeuern, Germany", "person": "Joseph von Fraunhofer", "sig": "Fraunhofer used the dark lines in sunlight as exact wavelength rulers to measure a glass's bending power precisely, so he could calculate a flawless lens instead of grinding by guess, a craft that died with him at 39.", "goal": "Both", "mech": "Fragility", "threads": ["Precision Optics"], "primary": "Precision Optics", "lat": 47.71, "lon": 11.4, "bo": ["Guinand's Stirring Process"], "en": ["Abbe's Diffraction Limit"], "country": ""}, {"id": "GNoME", "name": "GNoME", "kind": "Model", "year": 2023, "place": "London, England", "person": "DeepMind's researchers", "sig": "GNoME trained a neural network on millions of computed materials to predict which never-made crystals would hold together, proposing about 380,000 stable ones in a single sweep, the materials twin of protein-structure prediction.", "goal": "Both", "mech": "Convergence", "threads": ["Machine Learning", "Predict Before Building"], "primary": "Machine Learning", "lat": 51.51, "lon": -0.13, "bo": ["X-ray Crystallography", "Density Functional Theory", "The Deep-Learning Framework"], "en": [], "country": ""}, {"id": "Galileo's Telescope", "name": "Galileo's Telescope", "kind": "Measure", "year": 1609, "place": "Padua, Italy", "person": "Galileo Galilei", "sig": "Galileo ground a Dutch toy into a 30-power telescope and turned it on the sky, the lone-bench instrument for seeing far, twin to the microscope's seeing small.", "goal": "Both", "mech": "Convergence", "threads": ["Precision Optics"], "primary": "Precision Optics", "lat": 45.41, "lon": 11.88, "bo": [], "en": ["Leeuwenhoek's Microscope"], "country": ""}, {"id": "Gel Electrophoresis", "name": "Gel Electrophoresis", "kind": "Measure", "year": 1955, "place": "Toronto, Canada", "person": "Oliver Smithies", "sig": "Gel electrophoresis pulls DNA or protein through a jelly with an electric field so the pieces sort themselves by size, the cheap everyday workhorse under nearly every molecular-biology experiment.", "goal": "Both", "mech": "Convergence", "threads": ["Reading & Writing DNA"], "primary": "Reading & Writing DNA", "lat": 43.65, "lon": -79.38, "bo": [], "en": ["DNA Sequencing"], "country": ""}, {"id": "Generative Drug Design", "name": "Generative Drug Design", "kind": "Model", "year": 2019, "place": "Hong Kong", "person": "Alex Zhavoronkov, Insilico Medicine", "sig": "A model that invents new molecules to fit a target turns drug discovery from a search into a design problem.", "goal": "Both", "mech": "Convergence", "threads": ["Therapeutics", "Machine Learning"], "primary": "Therapeutics", "lat": 22.32, "lon": 114.17, "bo": ["The Deep-Learning Framework"], "en": [], "country": ""}, {"id": "Guinand's Stirring Process", "name": "Guinand's Stirring Process", "kind": "Make", "year": 1805, "place": "Les Brenets, Switzerland", "person": "Pierre-Louis Guinand", "sig": "Guinand's fireclay stirrer blended molten flint glass until it came out homogeneous and free of streaks, the guarded Swiss craft that finally made large, flawless lens blanks possible.", "goal": "Both", "mech": "Pace-layers", "threads": ["Precision Optics"], "primary": "Precision Optics", "lat": 47.06, "lon": 6.71, "bo": [], "en": ["Fraunhofer's Spectral-Line Glass"], "country": ""}, {"id": "Haber-Bosch", "name": "Haber-Bosch High-Pressure Synthesis", "kind": "Manufacture", "year": 1913, "place": "Ludwigshafen, Germany", "person": "Carl Bosch (BASF), on Fritz Haber's reaction", "sig": "Roughly half the nitrogen in your body passed through one of these reactors, and the firm that first built one could outlast a wartime blockade.", "goal": "Both", "mech": "Convergence", "threads": ["Critical Materials", "Feeding the World"], "primary": "Critical Materials", "lat": 49.4774, "lon": 8.4452, "bo": [], "en": [], "country": ""}, {"id": "High-Throughput Screening", "name": "High-Throughput Screening", "kind": "Make", "year": 1995, "place": "Pharma labs, USA and Europe", "person": "Pharma HTS groups (microplate from Gyula Takatsy)", "sig": "Made drug hunting a numbers game: a robot tests hundreds of thousands of compounds against one target in days, not years.", "goal": "1", "mech": "Convergence", "threads": ["Therapeutics"], "primary": "Therapeutics", "lat": 40.7, "lon": -74.4, "bo": [], "en": ["The Single-Use Bioreactor"], "country": ""}, {"id": "Hybrid Rice", "name": "Hybrid Rice", "kind": "Make", "year": 1970, "place": "Changsha, China", "person": "Yuan Longping", "sig": "It forced the world's most self-contained grain to cross-breed, and the extra vigour fed hundreds of millions.", "goal": "1", "mech": "Fragility", "threads": ["Feeding the World"], "primary": "Feeding the World", "lat": 28.2282, "lon": 112.9388, "bo": [], "en": [], "country": ""}, {"id": "ImageNet", "name": "ImageNet", "kind": "Model", "year": 2009, "place": "Princeton, New Jersey, USA", "person": "Fei-Fei Li", "sig": "ImageNet gave the whole field a single yardstick with 14 million labeled images, making supervised learning competitive and setting up the 2012 AlexNet result that opened the deep learning era.", "goal": "Both", "mech": "Convergence", "threads": ["Machine Learning"], "primary": "Machine Learning", "lat": 40.35, "lon": -74.66, "bo": [], "en": ["AlexNet"], "country": ""}, {"id": "Immersion Lithography", "name": "Immersion Lithography", "kind": "Make", "year": 2002, "place": "Hsinchu, Taiwan", "person": "Burn-Jeng Lin", "sig": "Slipping a film of water under the lens let the existing 193nm light print a dozen more chip generations, buying the industry a decade before EUV became unavoidable and helping ASML pull permanently ahead of Nikon in the process.", "goal": "Both", "mech": "Convergence", "threads": ["Chip Lithography"], "primary": "Chip Lithography", "lat": 24.81, "lon": 120.97, "bo": ["The Wafer Stepper"], "en": ["The High-Yield Process Recipe", "The EUV Machine"], "country": ""}, {"id": "Investment Casting", "name": "Single-Crystal Investment Casting", "kind": "Manufacture", "year": 1982, "place": "East Hartford, USA", "person": "Frank VerSnyder and the Pratt & Whitney foundry team", "sig": "Growing each jet-engine blade as one flawless crystal lets the engine run hot enough to be efficient, and the casting craft sits in only a few foundries.", "goal": "Both", "mech": "Pace-layers", "threads": ["Flight", "Machine Tools"], "primary": "Flight", "lat": 41.76, "lon": -72.61, "bo": [], "en": ["The Jet Engine"], "country": ""}, {"id": "Leeuwenhoek's Microscope", "name": "Leeuwenhoek's Microscope", "kind": "Measure", "year": 1676, "place": "Delft, Netherlands", "person": "Antonie van Leeuwenhoek", "sig": "Seeing microbes for the first time opened the path to germ theory, but only after two centuries because the lens-grinding skill died with Leeuwenhoek.", "goal": "1", "mech": "Fragility", "threads": ["Precision Optics", "Microscopy"], "primary": "Precision Optics", "lat": 52.01, "lon": 4.36, "bo": ["Galileo's Telescope"], "en": ["The Foldscope", "Abbe's Diffraction Limit", "Einstein's Displacement Equation"], "country": ""}, {"id": "Lipid Nanoparticles", "name": "Lipid Nanoparticles", "kind": "Make", "year": 2018, "place": "Vancouver, Canada", "person": "Pieter Cullis and colleagues (UBC, Acuitas, Arbutus)", "sig": "An mRNA vaccine is just a message; the lipid nanoparticle is the only thing that gets the message inside a cell alive.", "goal": "1", "mech": "Convergence", "threads": ["Therapeutics", "Engineering Biology"], "primary": "Therapeutics", "lat": 49.2606, "lon": -123.246, "bo": ["The Modified RNA Letter", "Flow Chemistry"], "en": [], "country": ""}, {"id": "MapReduce", "name": "MapReduce", "kind": "Model", "year": 2004, "place": "Mountain View, California, USA", "person": "Jeff Dean and Sanjay Ghemawat", "sig": "MapReduce let a programmer write two short functions and have the system spread them across thousands of cheap machines, handling the failures and the splitting, so web-scale data became something an ordinary engineer could process.", "goal": "Both", "mech": "Convergence", "threads": ["The Network"], "primary": "The Network", "lat": 37.39, "lon": -122.08, "bo": ["The Microprocessor"], "en": [], "country": ""}, {"id": "Mirror Galvanometer", "name": "Mirror Galvanometer", "kind": "Measure", "year": 1866, "place": "Glasgow, Scotland", "person": "William Thomson (Lord Kelvin)", "sig": "Reading a faint electrical current rather than boosting a loud one made the transatlantic cable work and established precise electrical measurement as the craft every later wire and radio leaned on.", "goal": "Both", "mech": "Convergence", "threads": ["Long-Distance Comms"], "primary": "Long-Distance Comms", "lat": 55.86, "lon": -4.25, "bo": [], "en": ["The Triode"], "country": ""}, {"id": "Monoclonal Antibodies", "name": "Monoclonal Antibodies", "kind": "Make", "year": 1975, "place": "Cambridge, England", "person": "Georges Köhler and César Milstein", "sig": "The hybridoma fuses an antibody-making cell with a cancer cell to spin out one exact antibody forever, the tool behind antibody drugs and nearly every rapid medical test.", "goal": "Both", "mech": "Convergence", "threads": ["Engineering Biology"], "primary": "Engineering Biology", "lat": 52.2, "lon": 0.12, "bo": ["The Vaccine"], "en": [], "country": ""}, {"id": "Negative Feedback", "name": "Negative Feedback", "kind": "Model", "year": 1927, "place": "New York, New York, USA", "person": "Harold Black", "sig": "Black's trick of feeding an amplifier's output back inverted, trading raw gain for accuracy, became the principle under every stable amplifier and control loop, from transcontinental phone lines to the servo that holds a cutting tool on its path.", "goal": "Both", "mech": "Convergence", "threads": ["Bell Labs", "Long-Distance Comms"], "primary": "Bell Labs", "lat": 40.71, "lon": -74.01, "bo": ["The Triode"], "en": ["Numerical Control"], "country": ""}, {"id": "Next-Generation Sequencing", "name": "Next-Generation Sequencing", "kind": "Measure", "year": 2006, "place": "Cambridge, England", "person": "Shankar Balasubramanian and David Klenerman (Solexa)", "sig": "It made reading DNA cheap enough to do at scale, dropping the cost of a human genome from billions to hundreds of dollars.", "goal": "Both", "mech": "Convergence", "threads": ["Reading & Writing DNA"], "primary": "Reading & Writing DNA", "lat": 52.2053, "lon": 0.1218, "bo": ["DNA Sequencing"], "en": ["DNA-Encoded Libraries"], "country": ""}, {"id": "Numerical Control", "name": "Numerical Control", "kind": "Make", "year": 1949, "place": "Traverse City, Michigan, USA", "person": "John Parsons, MIT Servo Lab", "sig": "America invented computer-controlled machining in 1952 but never made it cheap, handing the production lead to Japan's FANUC two decades later.", "goal": "2", "mech": "Convergence", "threads": ["Machine Tools"], "primary": "Machine Tools", "lat": 44.76, "lon": -85.62, "bo": ["The Production Grinder", "Negative Feedback"], "en": ["The Mass-Produced CNC Controller"], "country": ""}, {"id": "PCR", "name": "PCR", "kind": "Make", "year": 1983, "place": "Emeryville, California, USA", "person": "Kary Mullis", "sig": "Cheap, repeatable DNA copying is the enabling step that made reading, sequencing, and editing DNA practical at bench scale and eventually at global scale.", "goal": "Both", "mech": "Convergence", "threads": ["Reading & Writing DNA"], "primary": "Reading & Writing DNA", "lat": 37.83, "lon": -122.29, "bo": ["DNA Synthesis"], "en": ["CRISPR-Cas9"], "country": ""}, {"id": "Packet Switching", "name": "Packet Switching", "kind": "Model", "year": 1965, "place": "Teddington, United Kingdom", "person": "Donald Davies (with Paul Baran)", "sig": "Cutting a message into small numbered packets that each find their own route is the switching idea every computer network runs on, and because it was published openly the lead pooled in the gear and protocols built on top of it.", "goal": "1", "mech": "Convergence", "threads": ["The Network"], "primary": "The Network", "lat": 51.43, "lon": -0.33, "bo": ["The Bit"], "en": ["The Router", "TCP-IP"], "country": ""}, {"id": "Photolithography", "name": "Photolithography", "kind": "Make", "year": 1957, "place": "Washington, D.C., USA", "person": "Jay Lathrop and James Nall", "sig": "Printing circuits with light rather than cutting them by hand made identical chips manufacturable by the wafer-load, and every chip since has been made this way.", "goal": "Both", "mech": "Convergence", "threads": ["Chip Lithography"], "primary": "Chip Lithography", "lat": 38.89, "lon": -77.03, "bo": ["Abbe's Diffraction Limit"], "en": ["The EUV Machine", "The Integrated Circuit", "The Wafer Stepper"], "country": ""}, {"id": "Project Echo", "name": "Project Echo", "kind": "Make", "year": 1960, "place": "Murray Hill, New Jersey, USA", "person": "John R. Pierce", "sig": "A passive mirror in orbit proved in one day that signals could be routed through space, clearing the path for active repeater satellites within two years.", "goal": "1", "mech": "Convergence", "threads": ["Long-Distance Comms", "Bell Labs"], "primary": "Long-Distance Comms", "lat": 40.68, "lon": -74.4, "bo": ["The R-7 Rocket"], "en": ["Telstar"], "country": ""}, {"id": "Public-Key Cryptography", "name": "Public-Key Cryptography (RSA)", "kind": "Model", "year": 1977, "place": "Cambridge, USA", "person": "Rivest, Shamir, Adleman", "sig": "RSA let two people who never met agree on a secret in the open, the trick that now guards almost every web page and bank login.", "goal": "Both", "mech": "Convergence", "threads": ["The Network"], "primary": "The Network", "lat": 42.36, "lon": -71.09, "bo": ["The Bit"], "en": [], "country": ""}, {"id": "Recombinant DNA", "name": "Recombinant DNA", "kind": "Make", "year": 1973, "place": "Stanford, California, USA", "person": "Stanley Cohen and Herbert Boyer", "sig": "Cut-and-paste gene editing was the first time anyone deliberately wrote a chosen gene into a living cell, opening the write layer of the DNA toolkit and seeding the Bay Area biotech industry.", "goal": "Both", "mech": "Convergence", "threads": ["Reading & Writing DNA", "Engineering Biology"], "primary": "Reading & Writing DNA", "lat": 37.43, "lon": -122.17, "bo": ["The Central Dogma"], "en": ["DNA Sequencing"], "country": ""}, {"id": "Sketchpad", "name": "Sketchpad", "kind": "Model", "year": 1963, "place": "Cambridge, Massachusetts, USA", "person": "Ivan Sutherland", "sig": "Sketchpad put a design inside the computer as geometry you could grab and the machine could keep correct, the seed of every CAD system and of the graphical screen itself.", "goal": "Both", "mech": "Convergence", "threads": ["Prototyping & CAD"], "primary": "Prototyping & CAD", "lat": 42.37, "lon": -71.11, "bo": [], "en": ["Smalltalk", "CATIA", "Electronic Design Automation"], "country": ""}, {"id": "Smalltalk", "name": "Smalltalk", "kind": "Model", "year": 1972, "place": "Palo Alto, California, USA", "person": "Alan Kay", "sig": "Smalltalk made the object, a small bundle of data plus the code that acts on it, the building block of software, a way of writing programs that almost every modern language went on to copy.", "goal": "Both", "mech": "Convergence", "threads": ["Software Abstraction"], "primary": "Software Abstraction", "lat": 37.44, "lon": -122.14, "bo": ["FORTRAN", "Sketchpad"], "en": [], "country": ""}, {"id": "TCP-IP", "name": "TCP/IP", "kind": "Model", "year": 1974, "place": "Stanford, California, USA", "person": "Vint Cerf and Bob Kahn", "sig": "TCP/IP let separately built networks hand packets to one another through gateways, turning many private networks into one internet that no one owned.", "goal": "Both", "mech": "Convergence", "threads": ["The Network", "Long-Distance Comms"], "primary": "The Network", "lat": 37.43, "lon": -122.17, "bo": ["The Bit", "Packet Switching", "The Router", "Ethernet"], "en": ["The Web", "The Scaled-Up Language Model"], "country": ""}, {"id": "Telstar", "name": "Telstar", "kind": "Make", "year": 1962, "place": "Murray Hill, New Jersey, USA", "person": "John R. Pierce and the Bell Labs team", "sig": "Two unrelated Bell Labs inventions, the transistor and the silicon solar cell, met in one orbiting machine and made live transatlantic television routine within months.", "goal": "Both", "mech": "Convergence", "threads": ["Long-Distance Comms", "Bell Labs"], "primary": "Long-Distance Comms", "lat": 40.68, "lon": -74.4, "bo": ["The Silicon Solar Cell", "Project Echo"], "en": [], "country": ""}, {"id": "The Bit", "name": "The Bit", "kind": "Model", "year": 1948, "place": "Murray Hill, New Jersey, USA", "person": "Claude Shannon", "sig": "Shannon's channel-capacity math set the speed limit for every communications link ever built, but because the paper was public the lead pooled downstream in the chips and gear that race against it.", "goal": "1", "mech": "Convergence", "threads": ["Long-Distance Comms", "Bell Labs"], "primary": "Long-Distance Comms", "lat": 40.68, "lon": -74.4, "bo": [], "en": ["Public-Key Cryptography", "Packet Switching", "TCP-IP"], "country": ""}, {"id": "The Breadboard", "name": "The Breadboard", "kind": "Make", "year": 1971, "place": "Derby, Connecticut, USA", "person": "Ronald Portugal", "sig": "The solderless breadboard made the first try of any circuit nearly free and instant, the cheap zero-to-one step where a lot of electronics begins.", "goal": "1", "mech": "Convergence", "threads": ["Prototyping & CAD"], "primary": "Prototyping & CAD", "lat": 41.32, "lon": -73.08, "bo": ["The Integrated Circuit"], "en": [], "country": ""}, {"id": "The CT Scanner", "name": "The CT Scanner", "kind": "Measure", "year": 1971, "place": "Hayes, England", "person": "Godfrey Hounsfield", "sig": "A plain X-ray flattens the body into one shadow; the CT scanner takes many shadows from many angles and lets a computer rebuild a clean slice.", "goal": "1", "mech": "Convergence", "threads": ["Therapeutics"], "primary": "Therapeutics", "lat": 51.51, "lon": -0.42, "bo": ["The X-ray"], "en": [], "country": ""}, {"id": "The Cavity Magnetron", "name": "The Cavity Magnetron", "kind": "Make", "year": 1940, "place": "Birmingham, England", "person": "John Randall and Harry Boot", "sig": "A palm-sized copper block that produced enough microwave power for airborne radar shifted the Battle of the Atlantic, but Britain could not manufacture it fast enough and handed the lead to American factories.", "goal": "Both", "mech": "Convergence", "threads": ["Long-Distance Comms", "Forced by War"], "primary": "Long-Distance Comms", "lat": 52.49, "lon": -1.89, "bo": ["The Triode"], "en": [], "country": ""}, {"id": "The Central Dogma", "name": "The Central Dogma", "kind": "Model", "year": 1958, "place": "Cambridge, England", "person": "Francis Crick", "sig": "Declaring that genetic information flows one way, from DNA to protein, reframed the cell as a text-processing system and made it possible to build tools that read, copy, and edit genes without touching the chemistry directly.", "goal": "1", "mech": "Convergence", "threads": ["Reading & Writing DNA"], "primary": "Reading & Writing DNA", "lat": 52.2, "lon": 0.12, "bo": ["The Wet-Fibre X-ray Camera"], "en": ["Recombinant DNA", "The Modified RNA Letter"], "country": ""}, {"id": "The Control Chart", "name": "The Control Chart", "kind": "Model", "year": 1924, "place": "Cicero, USA", "person": "Walter Shewhart", "sig": "Shewhart's chart split a process's wobble into normal noise to ignore and a real fault to chase, the published method that made mass production trustworthy and that Japan borrowed to take the manufacturing lead.", "goal": "Both", "mech": "Convergence", "threads": ["Bell Labs", "Machine Tools"], "primary": "Bell Labs", "lat": 41.84, "lon": -87.76, "bo": [], "en": ["The Toyota Production System"], "country": ""}, {"id": "The Crystal Rectifier", "name": "The Crystal Rectifier", "kind": "Make", "year": 1945, "place": "West Lafayette, Indiana, USA", "person": "the wartime crystal-rectifier program", "sig": "Wartime radar forced the US to grow ultra-pure germanium and silicon crystals at scale, and that purification craft was already waiting when Bell Labs built the first transistor in 1947.", "goal": "Both", "mech": "Convergence", "threads": ["Electronic Switching", "Bell Labs", "Forced by War"], "primary": "Electronic Switching", "lat": 40.43, "lon": -86.91, "bo": [], "en": ["The Transistor"], "country": ""}, {"id": "The Czochralski Puller", "name": "The Czochralski Puller", "kind": "Manufacture", "year": 1916, "place": "Berlin, Germany", "person": "Jan Czochralski, Gordon Teal", "sig": "Almost every computer chip and most solar cells are cut from a single silicon crystal pulled from a melt by Czochralski's machine, grown so pure that fewer than one atom in a billion is out of place.", "goal": "1", "mech": "Convergence", "threads": ["Electronic Switching", "Energy", "Bell Labs"], "primary": "Electronic Switching", "lat": 52.52, "lon": 13.4, "bo": [], "en": ["The EUV Machine", "The Transistor", "The Silicon Solar Cell", "The Integrated Circuit"], "country": ""}, {"id": "The Deep-Learning Framework", "name": "The Deep-Learning Framework", "kind": "Model", "year": 2015, "place": "Mountain View, California, USA", "person": "Google (TensorFlow) and Meta (PyTorch)", "sig": "TensorFlow and PyTorch let an ordinary programmer build a neural net in a few lines of Python without touching the chip, becoming the free floor every modern AI model is built on.", "goal": "Both", "mech": "Convergence", "threads": ["Portable Software", "Machine Learning"], "primary": "Portable Software", "lat": 37.39, "lon": -122.08, "bo": ["Backpropagation", "Unix and C", "The GPU"], "en": ["Generative Drug Design", "AlphaFold", "The Scaled-Up Language Model", "GNoME"], "country": ""}, {"id": "The EUV Machine", "name": "The EUV Machine", "kind": "Manufacture", "year": 2019, "place": "Veldhoven, Netherlands", "person": "ASML", "sig": "Every advanced chip in phones, data centers, and AI is printed by ASML's EUV machine, and despite the physics being public since 1986 no other company has built one.", "goal": "Both", "mech": "Convergence", "threads": ["Chip Lithography", "Precision Optics"], "primary": "Chip Lithography", "lat": 51.42, "lon": 5.37, "bo": ["The Czochralski Puller", "Photolithography", "The Laser", "The Wafer Stepper", "Immersion Lithography"], "en": ["The High-Yield Process Recipe"], "country": ""}, {"id": "The Electron Microscope", "name": "The Electron Microscope", "kind": "Measure", "year": 1931, "place": "Berlin, Germany", "person": "Ernst Ruska", "sig": "Electrons have wavelengths far shorter than light, so whoever built a working electron lens could see the virus, the atom, and the transistor junction that light can never reach.", "goal": "1", "mech": "Convergence", "threads": ["Microscopy", "Electron Microscopy", "Materials Characterization"], "primary": "Microscopy", "lat": 52.51, "lon": 13.32, "bo": ["The Mass Spectrograph", "The Matter Wave"], "en": ["The Scanning Tunneling Microscope", "Cryo-EM"], "country": ""}, {"id": "The F-1 Engine", "name": "The F-1 Engine", "kind": "Make", "year": 1967, "place": "Canoga Park, California, USA", "person": "the F-1 engine team", "sig": "Combustion instability in large engines cannot be solved on paper, only on the test stand, so the Moon mission required about 2,000 firings to produce knowledge that lived in the people who watched enough engines fail.", "goal": "1", "mech": "Convergence", "threads": ["Reaching Orbit"], "primary": "Reaching Orbit", "lat": 34.2, "lon": -118.6, "bo": ["The R-7 Rocket"], "en": [], "country": ""}, {"id": "The FPGA", "name": "The FPGA", "kind": "Make", "year": 1985, "place": "San Jose, California, USA", "person": "Ross Freeman", "sig": "The FPGA let engineers rewire a chip's logic from a software file in seconds instead of ordering a new custom chip, and grew into a US-held industry for thirty-five years.", "goal": "Both", "mech": "Convergence", "threads": ["Prototyping & CAD", "Electronic Switching"], "primary": "Prototyping & CAD", "lat": 37.34, "lon": -121.89, "bo": ["The Integrated Circuit"], "en": [], "country": ""}, {"id": "The Factory Machine Shop", "name": "The Factory Machine Shop", "kind": "Make", "year": 1813, "place": "Waltham, Massachusetts, USA", "person": "Paul Moody, Boston Manufacturing Co", "sig": "An in-house shop that builds machines to run its own factory can spin out toolmakers and enter entirely new industries, as Lowell's shop did when it moved from looms to locomotives within 20 years.", "goal": "1", "mech": "Convergence", "threads": ["Machine Tools"], "primary": "Machine Tools", "lat": 42.38, "lon": -71.24, "bo": ["The Screw-Cutting Lathe"], "en": [], "country": ""}, {"id": "The Falcon 9", "name": "The Falcon 9", "kind": "Make", "year": 2015, "place": "Hawthorne, California, USA", "person": "SpaceX", "sig": "Landing and reflying the first stage cut the cost of reaching orbit by roughly 20x compared to the Space Shuttle, shifting launch leadership from a government program to a private firm.", "goal": "Both", "mech": "Convergence", "threads": ["Reaching Orbit"], "primary": "Reaching Orbit", "lat": 33.92, "lon": -118.35, "bo": ["The Space Shuttle", "CATIA", "The Soyuz"], "en": [], "country": ""}, {"id": "The Foldscope", "name": "The Foldscope", "kind": "Measure", "year": 2014, "place": "Stanford, California, USA", "person": "Manu Prakash", "sig": "A dollar-cost, freely published paper microscope shows that a tool with no moat can still spread scientific capability to places a $10,000 brass instrument never reached.", "goal": "2", "mech": "Convergence", "threads": ["Precision Optics"], "primary": "Precision Optics", "lat": 37.43, "lon": -122.17, "bo": ["Leeuwenhoek's Microscope", "Abbe's Diffraction Limit"], "en": [], "country": ""}, {"id": "The GPU", "name": "The GPU", "kind": "Make", "year": 2006, "place": "Santa Clara, California, USA", "person": "NVIDIA", "sig": "CUDA turned gaming cards into cheap parallel computers, and that substrate is what let AlexNet cut image-recognition error by 11 points in 2012, concentrating AI leadership in whoever controlled the compute.", "goal": "Both", "mech": "Convergence", "threads": ["Electronic Switching", "Machine Learning"], "primary": "Electronic Switching", "lat": 37.35, "lon": -121.95, "bo": ["The Microprocessor"], "en": ["The Scaled-Up Language Model", "AlexNet", "The Deep-Learning Framework"], "country": ""}, {"id": "The Gas Centrifuge", "name": "The Gas Centrifuge", "kind": "Manufacture", "year": 1956, "place": "Sukhumi, Georgia", "person": "Gernot Zippe", "sig": "Zippe's centrifuge spins uranium gas so fast the slightly heavier isotope drifts outward, and chained by the thousands it sorts the rare fissile uranium from the common kind, the gate every reactor and bomb must pass through.", "goal": "Both", "mech": "Pace-layers", "threads": ["Critical Materials"], "primary": "Critical Materials", "lat": 43.0, "lon": 41.02, "bo": ["The Mass Spectrograph"], "en": [], "country": ""}, {"id": "The Go-No-Go Gauge", "name": "The Go/No-Go Gauge", "kind": "Measure", "year": 1785, "place": "Vincennes, France", "person": "Honore Blanc", "sig": "A part that must slide into one steel check and stop at a second comes out the same size in any worker's hands, so parts made far apart still fit together.", "goal": "1", "mech": "Convergence", "threads": ["Machine Tools"], "primary": "Machine Tools", "lat": 48.85, "lon": 2.44, "bo": [], "en": ["The Moving Assembly Line", "The Universal Miller"], "country": ""}, {"id": "The Graphite Anode", "name": "The Graphite Anode", "kind": "Manufacture", "year": 2023, "place": "Heilongjiang, China", "person": "China's anode-material makers", "sig": "Rounding and acid-purifying graphite to battery grade is the materials-processing chokepoint of the lithium battery, and China holds nearly all of it.", "goal": "Both", "mech": "Pace-layers", "threads": ["Electricity & Batteries", "Critical Materials"], "primary": "Electricity & Batteries", "lat": 45.3, "lon": 130.97, "bo": [], "en": ["Battery-Line Equipment", "The Lithium-Ion Battery"], "country": ""}, {"id": "The High-Yield Process Recipe", "name": "The High-Yield Process Recipe", "kind": "Manufacture", "year": 1987, "place": "Hsinchu, Taiwan", "person": "Morris Chang and TSMC's process engineers", "sig": "The hand-tuned recipe of more than a thousand exact steps, learned wafer by wafer, is what lets TSMC make over 90% of the world's leading-edge chips while rivals running the same machines cannot match it.", "goal": "Both", "mech": "Convergence", "threads": ["Chip Lithography"], "primary": "Chip Lithography", "lat": 24.8, "lon": 120.97, "bo": ["The Integrated Circuit", "Electronic Design Automation", "Immersion Lithography", "The EUV Machine"], "en": [], "country": ""}, {"id": "The Hypervisor", "name": "The Hypervisor", "kind": "Make", "year": 1967, "place": "Cambridge, Massachusetts, USA", "person": "Robert Creasy and Mendel Rosenblum", "sig": "The hypervisor lets one physical computer pretend to be many separate, fully isolated ones, the tool that decades later turned computing into something you rent by the hour.", "goal": "Both", "mech": "Convergence", "threads": ["The Network"], "primary": "The Network", "lat": 42.37, "lon": -71.11, "bo": ["The Microprocessor"], "en": [], "country": ""}, {"id": "The Integrated Circuit", "name": "The Integrated Circuit", "kind": "Make", "year": 1959, "place": "Dallas, Texas, USA", "person": "Jack Kilby and Robert Noyce", "sig": "Printing all parts and wires onto one flat silicon chip eliminated hand-wiring and let photolithography manufacture millions of circuits in parallel, starting 60 years of compounding compute leadership in the US.", "goal": "Both", "mech": "Convergence", "threads": ["Electronic Switching", "Chip Lithography"], "primary": "Electronic Switching", "lat": 32.78, "lon": -96.8, "bo": ["The Czochralski Puller", "The Transistor", "Photolithography"], "en": ["The MOSFET", "Unix and C", "The Breadboard", "Atomic Layer Deposition", "Electronic Design Automation", "The FPGA", "The High-Yield Process Recipe"], "country": ""}, {"id": "The Jet Engine", "name": "The Jet Engine", "kind": "Make", "year": 1937, "place": "Rugby, England", "person": "Frank Whittle", "sig": "A turbojet burns fuel near the melting point of its own blades, so leadership in jet flight became leadership in metal that survives heat, the limit investment casting would later push back.", "goal": "Both", "mech": "Convergence", "threads": ["Energy", "Flight"], "primary": "Energy", "lat": 52.37, "lon": -1.26, "bo": ["Investment Casting"], "en": [], "country": ""}, {"id": "The Laser", "name": "The Laser", "kind": "Make", "year": 1960, "place": "Malibu, USA", "person": "Theodore Maiman", "sig": "The laser turned light into a tool you could point, time, and tune, and almost every precise machine that came after taps into it.", "goal": "Both", "mech": "Convergence", "threads": ["Precision Optics", "Long-Distance Comms"], "primary": "Precision Optics", "lat": 34.0259, "lon": -118.7798, "bo": [], "en": ["The EUV Machine", "DNA Sequencing"], "country": ""}, {"id": "The Lithium-Ion Battery", "name": "The Lithium-Ion Battery", "kind": "Make", "year": 1991, "place": "Tokyo, Japan", "person": "Akira Yoshino, John Goodenough, Stanley Whittingham (Sony)", "sig": "A cell that shuttles lithium ions between a layered oxide and carbon stored nearly twice the energy per kilogram of the batteries it replaced, and made modern portable electronics possible.", "goal": "Both", "mech": "Convergence", "threads": ["Electricity & Batteries"], "primary": "Electricity & Batteries", "lat": 35.6304, "lon": 139.74, "bo": ["The Graphite Anode", "Volta's Pile"], "en": [], "country": ""}, {"id": "The MOSFET", "name": "The MOSFET", "kind": "Make", "year": 1960, "place": "Murray Hill, New Jersey, USA", "person": "Mohamed Atalla and Dawon Kahng", "sig": "A transistor defined entirely by flat printed layers on a silicon oxide surface can be shrunk and printed a billion at a time, which is the physical fact that Moore's law and every digital device since 1960 rides on.", "goal": "1", "mech": "Convergence", "threads": ["Electronic Switching", "Bell Labs"], "primary": "Electronic Switching", "lat": 40.68, "lon": -74.4, "bo": ["The Integrated Circuit"], "en": ["DRAM", "The Microprocessor"], "country": ""}, {"id": "The Machine-Tool VRA", "name": "The Machine-Tool VRA", "kind": "Manufacture", "year": 1982, "place": "Washington, D.C., USA", "person": "Houdaille, the NMTBA, Reagan administration", "sig": "Trade barriers imposed in 1986 failed to recover the US machine-tool industry because the tacit craft had already moved to Japan and Germany, showing that a slow-layer capability cannot be rebuilt on the timeline of trade policy.", "goal": "2", "mech": "Pace-layers", "threads": ["Machine Tools"], "primary": "Machine Tools", "lat": 38.9, "lon": -77.04, "bo": ["The Mass-Produced CNC Controller"], "en": [], "country": ""}, {"id": "The Mass Spectrograph", "name": "The Mass Spectrograph", "kind": "Measure", "year": 1919, "place": "Cambridge, England", "person": "Francis Aston", "sig": "Aston's mass spectrograph sorted atoms by weight by bending them through electric and magnetic fields, revealing that one element can come in several masses, the isotopes, and giving chemistry a balance for the unseen.", "goal": "Both", "mech": "Convergence", "threads": ["Materials Characterization", "Atomic Theory"], "primary": "Materials Characterization", "lat": 52.21, "lon": 0.12, "bo": ["Einstein's Displacement Equation"], "en": ["The Gas Centrifuge", "The Electron Microscope"], "country": ""}, {"id": "The Mass-Produced CNC Controller", "name": "The Mass-Produced CNC Controller", "kind": "Manufacture", "year": 1956, "place": "Tokyo, Japan", "person": "Seiuemon Inaba, Fujitsu FANUC", "sig": "The controller is the brain that reads a program and drives a cutting machine to a thousandth of an inch, and making it cheap and off-the-shelf handed the machine-tool lead from the country that invented it to the country that mass-produced it.", "goal": "2", "mech": "Convergence", "threads": ["Machine Tools"], "primary": "Machine Tools", "lat": 35.69, "lon": 139.69, "bo": ["Numerical Control", "The Microcontroller"], "en": ["The Machine-Tool VRA"], "country": ""}, {"id": "The Matter Wave", "name": "The Matter Wave", "kind": "Model", "year": 1924, "place": "Paris, France", "person": "Louis de Broglie", "sig": "De Broglie's free published thesis showed electrons behave as waves thousands of times shorter than light, making a new class of microscope conceivable, but the lead went to whichever country actually built the tool.", "goal": "Both", "mech": "Convergence", "threads": ["Microscopy", "Electron Microscopy"], "primary": "Microscopy", "lat": 48.85, "lon": 2.35, "bo": ["Abbe's Diffraction Limit"], "en": ["The Electron Microscope"], "country": ""}, {"id": "The Microcontroller", "name": "The Microcontroller", "kind": "Make", "year": 1974, "place": "Dallas, Texas, USA", "person": "Gary Boone and the TI team", "sig": "Collapsing a whole computer onto one $2 chip let manufacturers hide programmable intelligence inside any product, from toys to machine-tool controllers, and the lead migrated to whoever built the cheapest capable version.", "goal": "Both", "mech": "Convergence", "threads": ["Electronic Switching"], "primary": "Electronic Switching", "lat": 32.78, "lon": -96.8, "bo": ["The Microprocessor"], "en": ["The Mass-Produced CNC Controller"], "country": ""}, {"id": "The Microprocessor", "name": "The Microprocessor", "kind": "Make", "year": 1971, "place": "Santa Clara, California, USA", "person": "Hoff, Faggin, Mazor, and Shima", "sig": "Putting a general-purpose CPU on one buyable chip meant any machine could be given a programmable mind, and the craft of laying that mind out in silicon spread to whoever could learn it, as Shima carried it to Japan.", "goal": "Both", "mech": "Convergence", "threads": ["Electronic Switching"], "primary": "Electronic Switching", "lat": 37.35, "lon": -121.95, "bo": ["The MOSFET"], "en": ["The GPU", "The Hypervisor", "The Microcontroller", "MapReduce"], "country": ""}, {"id": "The Modified RNA Letter", "name": "The Modified RNA Letter", "kind": "Make", "year": 2005, "place": "Philadelphia, Pennsylvania, USA", "person": "Katalin Karikó", "sig": "Swapping one RNA letter, uridine for pseudouridine, stopped synthetic mRNA from inflaming the body and turned it into a usable medicine, the edit under every mRNA vaccine.", "goal": "1", "mech": "Fragility", "threads": ["Reading & Writing DNA", "Engineering Biology"], "primary": "Reading & Writing DNA", "lat": 39.95, "lon": -75.17, "bo": ["The Central Dogma"], "en": ["Lipid Nanoparticles"], "country": ""}, {"id": "The Moving Assembly Line", "name": "The Moving Assembly Line", "kind": "Manufacture", "year": 1913, "place": "Highland Park, USA", "person": "Henry Ford", "sig": "Ford's moving conveyor brought the work to the worker instead of the worker to the work, cutting a Model T from twelve hours to ninety minutes and setting the template for twentieth-century mass production.", "goal": "Both", "mech": "Convergence", "threads": ["Machine Tools"], "primary": "Machine Tools", "lat": 42.41, "lon": -83.1, "bo": ["The Go-No-Go Gauge"], "en": ["The Toyota Production System"], "country": ""}, {"id": "The NdFeB Magnet", "name": "The NdFeB Magnet", "kind": "Make", "year": 1982, "place": "Osaka, Japan", "person": "Masato Sagawa (Sumitomo Special Metals)", "sig": "The strongest permanent magnet ever made, and the part that turns electric motors small enough to fit in a car, a missile fin, or a wind-turbine hub.", "goal": "Both", "mech": "Convergence", "threads": ["Critical Materials"], "primary": "Critical Materials", "lat": 34.6937, "lon": 135.5023, "bo": ["The Solvent-Extraction Cascade"], "en": [], "country": ""}, {"id": "The Nuclear Pile", "name": "The Nuclear Pile", "kind": "Make", "year": 1942, "place": "Chicago, USA", "person": "Enrico Fermi", "sig": "It was the first machine to hold a nuclear chain reaction steady instead of letting it run away, so fission could be used for power and for weapons.", "goal": "Both", "mech": "Convergence", "threads": ["Energy", "Forced by War"], "primary": "Energy", "lat": 41.7918, "lon": -87.6011, "bo": [], "en": [], "country": ""}, {"id": "The Production Grinder", "name": "The Production Grinder", "kind": "Make", "year": 1908, "place": "Worcester, Massachusetts, USA", "person": "Charles Norton, the auto industry", "sig": "The automobile demanded hardened-steel parts by the thousand, and the only tool that could cut them was Norton's heavy grinder, pulling the machine-tool trade's center from New England to Detroit and Cincinnati.", "goal": "2", "mech": "Convergence", "threads": ["Machine Tools"], "primary": "Machine Tools", "lat": 42.26, "lon": -71.8, "bo": ["The Universal Miller"], "en": ["Numerical Control"], "country": ""}, {"id": "The Punch Card", "name": "The Punch Card", "kind": "Make", "year": 1954, "place": "Poughkeepsie, New York, USA", "person": "an IBM 704 programmer", "sig": "When a program was a deck of physical holes fed raw to one machine, it was both the beginning of stored-program computing and the problem the operating system had to solve: one job, one machine, no abstraction.", "goal": "1", "mech": "Convergence", "threads": ["Portable Software", "Software Abstraction"], "primary": "Portable Software", "lat": 41.7, "lon": -73.93, "bo": [], "en": ["FORTRAN", "Unix and C", "The Relational Model"], "country": ""}, {"id": "The R-7 Rocket", "name": "The R-7 Rocket", "kind": "Make", "year": 1957, "place": "Baikonur, Kazakhstan", "person": "Sergei Korolev", "sig": "The first rocket powerful enough to reach orbit, it gave the Soviet Union a decade-long lead in spaceflight and its descendants still carry people to orbit today.", "goal": "Both", "mech": "Convergence", "threads": ["Reaching Orbit", "Forced by War"], "primary": "Reaching Orbit", "lat": 45.96, "lon": 63.31, "bo": ["The V-2"], "en": ["The Soyuz", "Project Echo", "The F-1 Engine"], "country": ""}, {"id": "The Relational Model", "name": "The Relational Model", "kind": "Model", "year": 1970, "place": "San Jose, California, USA", "person": "Edgar Codd", "sig": "Codd's relational model stored data as plain tables you could question by logic instead of by knowing where each record physically sat, the idea under almost every database since.", "goal": "Both", "mech": "Convergence", "threads": ["Software Abstraction"], "primary": "Software Abstraction", "lat": 37.34, "lon": -121.89, "bo": ["The Punch Card"], "en": [], "country": ""}, {"id": "The Router", "name": "The Router", "kind": "Make", "year": 1969, "place": "Cambridge, Massachusetts, USA", "person": "Frank Heart and the BBN team", "sig": "The IMP was a dedicated box that took in packets and forwarded each toward its destination, the first node of the ARPANET and the ancestor of every internet router.", "goal": "Both", "mech": "Convergence", "threads": ["The Network"], "primary": "The Network", "lat": 42.39, "lon": -71.14, "bo": ["Packet Switching"], "en": ["Ethernet", "TCP-IP"], "country": ""}, {"id": "The Scaled-Up Language Model", "name": "The Scaled-Up Language Model", "kind": "Make", "year": 2020, "place": "San Francisco, California, USA", "person": "OpenAI", "sig": "Growing a Transformer to internet scale and then tuning it to follow plain instructions made a single model that does many tasks, but its published recipe meant the durable lead settled not in the model but in the chips and fabs that train and run it.", "goal": "Both", "mech": "Fragility", "threads": ["Machine Learning"], "primary": "Machine Learning", "lat": 37.77, "lon": -122.42, "bo": ["The GPU", "TCP-IP", "The Deep-Learning Framework", "The Transformer"], "en": [], "country": ""}, {"id": "The Scanning Tunneling Microscope", "name": "The Scanning Tunneling Microscope", "kind": "Measure", "year": 1981, "place": "Zurich, Switzerland", "person": "Gerd Binnig and Heinrich Rohrer", "sig": "The scanning tunneling microscope drags a needle one atom wide across a surface and feels each atom by the trickle of current that jumps the gap, the first tool to see and then move single atoms.", "goal": "Both", "mech": "Convergence", "threads": ["Materials Characterization", "Microscopy"], "primary": "Materials Characterization", "lat": 47.37, "lon": 8.54, "bo": ["The Electron Microscope"], "en": ["Cryo-EM"], "country": ""}, {"id": "The Screw-Cutting Lathe", "name": "The Screw-Cutting Lathe", "kind": "Make", "year": 1800, "place": "London, England", "person": "Henry Maudslay", "sig": "By moving precision out of the worker's hand and into the machine itself, Maudslay's lathe made it possible to build machines more exact than any craftsman, compounding Britain's lead in metal-cutting for generations.", "goal": "Both", "mech": "Convergence", "threads": ["Machine Tools"], "primary": "Machine Tools", "lat": 51.51, "lon": -0.13, "bo": ["The Water Frame"], "en": ["The Factory Machine Shop"], "country": ""}, {"id": "The Silicon Solar Cell", "name": "The Silicon Solar Cell", "kind": "Make", "year": 1954, "place": "Murray Hill, New Jersey, USA", "person": "Chapin, Fuller, and Pearson", "sig": "The same silicon-doping craft that made the transistor produced a cell that could power a satellite indefinitely in orbit, where no wire or battery could reach.", "goal": "1", "mech": "Convergence", "threads": ["Energy", "Long-Distance Comms", "Bell Labs"], "primary": "Energy", "lat": 40.68, "lon": -74.4, "bo": ["The Transistor", "The Czochralski Puller"], "en": ["Telstar"], "country": ""}, {"id": "The Single-Use Bioreactor", "name": "The Single-Use Bioreactor", "kind": "Manufacture", "year": 1996, "place": "Union, New Jersey, USA", "person": "Vijay Singh (Schering-Plough)", "sig": "It turns the cell-culture vessel into a pre-sterilized consumable, so a factory can switch products without cleaning a single tank.", "goal": "Both", "mech": "Pace-layers", "threads": ["Therapeutics"], "primary": "Therapeutics", "lat": 40.6976, "lon": -74.2632, "bo": ["Deep-Tank Fermentation", "High-Throughput Screening"], "en": ["Flow Chemistry"], "country": ""}, {"id": "The Solvent-Extraction Cascade", "name": "The Solvent-Extraction Cascade", "kind": "Manufacture", "year": 1972, "place": "Beijing, China", "person": "Xu Guangxian", "sig": "A published equation made rare-earth separation calculable, and the country that ran the math for fifty years now controls the metals that build motors and missiles.", "goal": "Both", "mech": "Pace-layers", "threads": ["Critical Materials"], "primary": "Critical Materials", "lat": 39.9906, "lon": 116.305, "bo": [], "en": ["The NdFeB Magnet"], "country": ""}, {"id": "The Soyuz", "name": "The Soyuz", "kind": "Make", "year": 2011, "place": "Baikonur, Kazakhstan", "person": "the Soyuz program", "sig": "When the US retired the Shuttle without a replacement, it had to buy seats on the same Soviet rocket lineage it once raced against, paying up to $90 million per seat for nine years.", "goal": "2", "mech": "Pace-layers", "threads": ["Reaching Orbit"], "primary": "Reaching Orbit", "lat": 45.96, "lon": 63.31, "bo": ["The R-7 Rocket"], "en": ["The Falcon 9"], "country": ""}, {"id": "The Space Shuttle", "name": "The Space Shuttle", "kind": "Make", "year": 1981, "place": "Cape Canaveral, Florida, USA", "person": "NASA", "sig": "The Shuttle proved a spaceplane could be reused but built it so that every flight still cost around a billion dollars, showing that reusability as an idea is not the same as reusability as an economics.", "goal": "1", "mech": "Convergence", "threads": ["Reaching Orbit"], "primary": "Reaching Orbit", "lat": 28.57, "lon": -80.65, "bo": [], "en": ["The Falcon 9"], "country": ""}, {"id": "The Spectroscope", "name": "The Spectroscope", "kind": "Measure", "year": 1859, "place": "Heidelberg, Germany", "person": "Robert Bunsen and Gustav Kirchhoff", "sig": "Bunsen and Kirchhoff's spectroscope split a flame's light into a barcode of sharp lines unique to each element, the first way to read what something is made of from its light alone, even a star's.", "goal": "Both", "mech": "Convergence", "threads": ["Materials Characterization", "Atomic Theory"], "primary": "Materials Characterization", "lat": 49.4, "lon": 8.67, "bo": [], "en": ["Einstein's Displacement Equation", "X-ray Crystallography"], "country": ""}, {"id": "The Steam Turbine", "name": "The Steam Turbine", "kind": "Make", "year": 1884, "place": "Gateshead, England", "person": "Charles Parsons", "sig": "It turned heat into spinning motion smoothly enough and fast enough to drive an electric generator, and still spins most of the world's power plants.", "goal": "Both", "mech": "Convergence", "threads": ["Energy"], "primary": "Energy", "lat": 54.96, "lon": -1.6, "bo": ["Watt's Steam Engine"], "en": [], "country": ""}, {"id": "The Toyota Production System", "name": "The Toyota Production System", "kind": "Manufacture", "year": 1950, "place": "Toyota City, Japan", "person": "Taiichi Ohno", "sig": "Toyota turned Ford's big-batch flow into a pull system that made only what the next step needed, cutting inventory and waste to almost nothing, the method the whole world later copied as lean.", "goal": "Both", "mech": "Pace-layers", "threads": ["Machine Tools"], "primary": "Machine Tools", "lat": 35.08, "lon": 137.16, "bo": ["The Control Chart", "The Moving Assembly Line"], "en": [], "country": ""}, {"id": "The Transformer", "name": "The Transformer", "kind": "Model", "year": 2017, "place": "Mountain View, California, USA", "person": "Vaswani and seven others (Google)", "sig": "Google published the Transformer architecture freely in 2017, giving the entire industry the shape that scales with compute, so the lead pooled not in the design but in whoever could afford the largest clusters to run it.", "goal": "Both", "mech": "Fragility", "threads": ["Machine Learning"], "primary": "Machine Learning", "lat": 37.39, "lon": -122.08, "bo": ["AlexNet"], "en": ["AlphaFold", "The Scaled-Up Language Model"], "country": ""}, {"id": "The Transistor", "name": "The Transistor", "kind": "Make", "year": 1947, "place": "Murray Hill, New Jersey, USA", "person": "Bardeen, Brattain, and Shockley", "sig": "Solid crystal replacing the vacuum tube meant the same part could amplify a phone call or flip a binary switch, opening both the long-distance network and the computer to the same piece of Bell semiconductor science.", "goal": "Both", "mech": "Convergence", "threads": ["Electronic Switching", "Long-Distance Comms", "Bell Labs"], "primary": "Electronic Switching", "lat": 40.68, "lon": -74.4, "bo": ["The Triode", "The Czochralski Puller", "The Crystal Rectifier"], "en": ["Unix and C", "The Silicon Solar Cell", "The Integrated Circuit"], "country": ""}, {"id": "The Triode", "name": "The Triode", "kind": "Make", "year": 1915, "place": "New York, New York, USA", "person": "Lee de Forest and Harold Arnold", "sig": "The first reliable electronic amplifier made long-distance telephony and radio possible from the same part, concentrating a deep US lead in both industries until the tube hit limits the transistor was built to fix.", "goal": "Both", "mech": "Convergence", "threads": ["Electronic Switching", "Long-Distance Comms", "Bell Labs"], "primary": "Electronic Switching", "lat": 40.71, "lon": -74.01, "bo": ["Mirror Galvanometer"], "en": ["The Transistor", "Negative Feedback", "The Cavity Magnetron"], "country": ""}, {"id": "The Universal Miller", "name": "The Universal Miller", "kind": "Make", "year": 1861, "place": "Providence, Rhode Island, USA", "person": "Brown and Sharpe", "sig": "A machine built to cut one part for one war contract became a general-purpose metalworking tool that crossed industry after industry, letting New England shops supply sewing machines, shoes, and rifles from the same equipment.", "goal": "1", "mech": "Convergence", "threads": ["Machine Tools"], "primary": "Machine Tools", "lat": 41.82, "lon": -71.41, "bo": ["The Go-No-Go Gauge"], "en": ["The Production Grinder"], "country": ""}, {"id": "The V-2", "name": "The V-2", "kind": "Make", "year": 1944, "place": "Peenemünde, Germany", "person": "Wernher von Braun", "sig": "The turbopump-fed, regeneratively cooled engine von Braun proved at Peenemunde is the template almost every large rocket since has copied, and the lead it represented walked to America with the engineers who built it.", "goal": "Both", "mech": "Convergence", "threads": ["Reaching Orbit", "Forced by War"], "primary": "Reaching Orbit", "lat": 54.14, "lon": 13.77, "bo": [], "en": ["The R-7 Rocket"], "country": ""}, {"id": "The Vaccine", "name": "The Vaccine", "kind": "Make", "year": 1796, "place": "Berkeley, England", "person": "Edward Jenner", "sig": "It is the method for teaching the immune system to fight a disease it has not yet met, the root of every vaccine since.", "goal": "Both", "mech": "Convergence", "threads": ["Therapeutics"], "primary": "Therapeutics", "lat": 51.69, "lon": -2.46, "bo": [], "en": ["Monoclonal Antibodies"], "country": ""}, {"id": "The Variable-Density Tunnel", "name": "The Variable-Density Tunnel", "kind": "Measure", "year": 1933, "place": "Hampton, Virginia, USA", "person": "Eastman Jacobs, Kenneth Ward, and Robert Pinkerton", "sig": "By pressurizing a small tunnel to 20 atmospheres, NACA engineers made a model behave like a full-size wing and published the results as a free catalog that American planemakers used for decades without having to test each shape themselves.", "goal": "Both", "mech": "Convergence", "threads": ["Predict Before Building", "Flight"], "primary": "Predict Before Building", "lat": 37.08, "lon": -76.36, "bo": [], "en": ["Computational Fluid Dynamics"], "country": ""}, {"id": "The Wafer Stepper", "name": "The Wafer Stepper", "kind": "Manufacture", "year": 1978, "place": "Bedford, Massachusetts, USA", "person": "GCA's engineers", "sig": "The wafer stepper prints a chip's pattern one small field at a time and steps across the wafer, the machine at the heart of chipmaking, whose leadership slid from America to Japan to one Dutch firm.", "goal": "Both", "mech": "Pace-layers", "threads": ["Chip Lithography"], "primary": "Chip Lithography", "lat": 42.49, "lon": -71.28, "bo": ["Photolithography"], "en": ["Immersion Lithography", "The EUV Machine"], "country": ""}, {"id": "The Water Frame", "name": "The Water Frame", "kind": "Manufacture", "year": 1771, "place": "Cromford, Derbyshire, UK", "person": "Richard Arkwright", "sig": "Arkwright's mill at Cromford was the first place where powered machines ran continuously under one roof with hired workers organized around them, the template for industrial manufacturing that Britain guarded until one trained hand carried it to America.", "goal": "Both", "mech": "Fragility", "threads": ["Machine Tools"], "primary": "Machine Tools", "lat": 53.11, "lon": -1.56, "bo": [], "en": ["The Screw-Cutting Lathe"], "country": ""}, {"id": "The Web", "name": "The Web", "kind": "Make", "year": 1989, "place": "Geneva, Switzerland", "person": "Tim Berners-Lee", "sig": "It turned the internet from a network only experts could reach into a web of linked pages anyone could open and write.", "goal": "Both", "mech": "Convergence", "threads": ["The Network"], "primary": "The Network", "lat": 46.23, "lon": 6.06, "bo": ["TCP-IP"], "en": [], "country": ""}, {"id": "The Wet-Fibre X-ray Camera", "name": "The Wet-Fibre X-ray Camera", "kind": "Measure", "year": 1952, "place": "London, England", "person": "Rosalind Franklin", "sig": "A tilting X-ray camera that kept a single DNA fibre at just the right damp let the molecule's spiral shape print itself onto film, giving Watson and Crick the numbers they built the double helix from.", "goal": "1", "mech": "Convergence", "threads": ["Reading & Writing DNA", "Materials Characterization"], "primary": "Reading & Writing DNA", "lat": 51.51, "lon": -0.13, "bo": ["X-ray Crystallography"], "en": ["The Central Dogma"], "country": ""}, {"id": "The X-ray", "name": "The X-ray", "kind": "Measure", "year": 1895, "place": "Würzburg, Germany", "person": "Wilhelm Röntgen", "sig": "It let doctors look at the bone inside living flesh without a single cut.", "goal": "1", "mech": "Convergence", "threads": ["Therapeutics"], "primary": "Therapeutics", "lat": 49.79, "lon": 9.93, "bo": [], "en": ["X-ray Crystallography", "The CT Scanner"], "country": ""}, {"id": "Unix and C", "name": "Unix and C", "kind": "Make", "year": 1969, "place": "Murray Hill, New Jersey, USA", "person": "Ken Thompson and Dennis Ritchie", "sig": "Unix and C decoupled software from the hardware it ran on, and an antitrust decree that barred AT&T from selling software forced Bell Labs to give it away, spreading the standard so widely that no one ended up owning it.", "goal": "Both", "mech": "Fragility", "threads": ["Portable Software", "Bell Labs", "Software Abstraction"], "primary": "Portable Software", "lat": 40.68, "lon": -74.4, "bo": ["The Transistor", "The Punch Card", "FORTRAN", "The Integrated Circuit"], "en": ["The Deep-Learning Framework"], "country": ""}, {"id": "Volta's Pile", "name": "Volta's Pile", "kind": "Make", "year": 1800, "place": "Pavia, Italy", "person": "Alessandro Volta", "sig": "Volta's stack of zinc and copper discs was the first thing that could pour a steady electric current, the source every wire, motor, and circuit since has needed.", "goal": "Both", "mech": "Convergence", "threads": ["Electricity & Batteries"], "primary": "Electricity & Batteries", "lat": 45.19, "lon": 9.16, "bo": [], "en": ["The Lithium-Ion Battery", "Faraday's Induction Ring"], "country": ""}, {"id": "Watt's Steam Engine", "name": "Watt's Steam Engine", "kind": "Make", "year": 1769, "place": "Birmingham, England", "person": "James Watt", "sig": "It cut the fuel a steam engine burned by most of what it used, so power no longer had to sit next to a coal pit.", "goal": "Both", "mech": "Convergence", "threads": ["Energy"], "primary": "Energy", "lat": 52.49, "lon": -1.89, "bo": [], "en": ["The Steam Turbine"], "country": ""}, {"id": "X-ray Crystallography", "name": "X-ray Crystallography", "kind": "Measure", "year": 1913, "place": "Leeds, England", "person": "William Henry and William Lawrence Bragg", "sig": "X-ray crystallography reads the exact arrangement of atoms in a crystal from how it scatters X-rays, the master tool for the structure of metals, minerals, drugs, chips, and the molecules of life.", "goal": "Both", "mech": "Convergence", "threads": ["Materials Characterization"], "primary": "Materials Characterization", "lat": 53.8, "lon": -1.55, "bo": ["The X-ray", "The Spectroscope"], "en": ["The Wet-Fibre X-ray Camera", "AlphaFold", "GNoME"], "country": ""}];